#include<bits/stdc++.h>
#define ll long long
using namespace std;
const int MAXN=2e4+5,MAXM=1e2+5;
int n,a[MAXM],b[MAXN],f[MAXN],m,ans=INT_MIN;
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	scanf("%d%d",&n,&m);
	for(int i=0;i<m;++i)scanf("%d",a+i);
	for(int i=0;i<n;++i)scanf("%d",b+i);
	f[0]=b[0];
	for(int i=1;i<n*2;++i){
		f[i]=INT_MIN;
		for(int j=0;j<m;++j)
			if(i-a[j]>=0&&f[i-a[j]]!=INT_MIN)f[i]=max(f[i],f[i-a[j]]+b[i]);
	}for(int i=n-1;i<2*n;++i)ans=max(ans,f[i]);
	printf("%d",ans);
	return false;
}
//f(i)=max(f(i),f(i-a(j))+b(i))
